/**
 * #### Network access mode: public internet (default), VPC-only, or VPC with security-group scoping.
 *
 * ---
 *
 * Even in `internet` mode, access requires IAM credentials. VPC modes add network-level isolation.
 * **Warning:** you cannot switch between `internet` and `vpc`/`scoping-workloads-in-vpc` after creation.
 *
 * **Example (YAML):**
 *
 * ```yaml
 * resources:
 *   searchEngine:
 *     type: open-search-domain
 *     properties:
 *       version: '2.17'
 *       clusterConfig:
 *         instanceType: r6g.large.search
 *         instanceCount: 2
 *       storage:
 *         size: 50
 *       accessibility:
 *         accessibilityMode: vpc
 *   indexer:
 *     type: function
 *     properties:
 *       packaging:
 *         type: stacktape-lambda-buildpack
 *         properties:
 *           entryfilePath: src/indexer.ts
 *       joinDefaultVpc: true
 * ```
 *
 * **Example (TypeScript):**
 *
 * ```ts
 * import { OpenSearchDomain, LambdaFunction, defineConfig } from 'stacktape';
 *
 * export default defineConfig(() => {
 *   const searchEngine = new OpenSearchDomain({
 *     version: '2.17',
 *     clusterConfig: {
 *       instanceType: 'r6g.large.search',
 *       instanceCount: 2
 *     },
 *     storage: {
 *       size: 50
 *     },
 *     accessibility: {
 *       accessibilityMode: 'vpc'
 *     }
 *   });
 *   const indexer = new LambdaFunction({
 *     packaging: {
 *       type: 'stacktape-lambda-buildpack',
 *       properties: {
 *         entryfilePath: 'src/indexer.ts'
 *       }
 *     },
 *     joinDefaultVpc: true
 *   });
 *   return { resources: { searchEngine, indexer } };
 * });
 * ```
 */
export interface OpenSearchAccessibility {
  /**
   * #### How the domain can be reached.
   *
   * ---
   *
   * - **`internet`**: Accessible from anywhere (still requires IAM credentials).
   * - **`vpc`**: Only accessible from resources inside your VPC (functions with `joinDefaultVpc: true`, containers, batch jobs).
   * - **`scoping-workloads-in-vpc`**: Like `vpc`, but also requires security-group access via `connectTo`.
   *
   * **Cannot be changed after creation** — switching between internet and VPC modes requires a new domain.
   *
   *
   * **Example (YAML):**
   *
   * ```yaml
   * resources:
   *   searchEngine:
   *     type: open-search-domain
   *     properties:
   *       version: '2.17'
   *       clusterConfig:
   *         instanceType: r6g.large.search
   *         instanceCount: 2
   *       storage:
   *         size: 50
   *       accessibility:
   *         accessibilityMode: scoping-workloads-in-vpc
   *   indexer:
   *     type: function
   *     properties:
   *       packaging:
   *         type: stacktape-lambda-buildpack
   *         properties:
   *           entryfilePath: src/indexer.ts
   *       joinDefaultVpc: true
   *       connectTo:
   *         - searchEngine
   * ```
   *
   * **Example (TypeScript):**
   *
   * ```ts
   * import { OpenSearchDomain, LambdaFunction, defineConfig } from 'stacktape';
   *
   * export default defineConfig(() => {
   *   const searchEngine = new OpenSearchDomain({
   *     version: '2.17',
   *     clusterConfig: {
   *       instanceType: 'r6g.large.search',
   *       instanceCount: 2
   *     },
   *     storage: {
   *       size: 50
   *     },
   *     accessibility: {
   *       accessibilityMode: 'scoping-workloads-in-vpc'
   *     }
   *   });
   *   const indexer = new LambdaFunction({
   *     packaging: {
   *       type: 'stacktape-lambda-buildpack',
   *       properties: {
   *         entryfilePath: 'src/indexer.ts'
   *       }
   *     },
   *     joinDefaultVpc: true,
   *     connectTo: [searchEngine]
   *   });
   *   return { resources: { searchEngine, indexer } };
   * });
   * ```
   */
  accessibilityMode: "internet" | "scoping-workloads-in-vpc" | "vpc";
}
/**
 * #### Shared file storage that multiple containers can read/write simultaneously.
 *
 * ---
 *
 * Persistent, elastic (grows/shrinks automatically), and accessible from any container in your stack
 * via `volumeMounts`. Use for shared uploads, CMS media, ML model files, or anything that needs to
 * survive container restarts. Pay only for storage used (~$0.30/GB/month for standard access).
 *
 * **Example (YAML):**
 *
 * ```yaml
 * resources:
 *   sharedStorage:
 *     type: efs-filesystem
 *     properties:
 *       backupEnabled: true
 *       throughputMode: elastic
 *   apiWorkload:
 *     type: multi-container-workload
 *     properties:
 *       containers:
 *         - name: api-container
 *           packaging:
 *             type: prebuilt-image
 *             properties:
 *               image: my-repo/my-api
 *           volumeMounts:
 *             - type: efs
 *               properties:
 *                 efsFilesystemName: sharedStorage
 *                 mountPath: /data
 *       resources:
 *         cpu: 1
 *         memory: 2048
 * ```
 *
 * **Example (TypeScript):**
 *
 * ```ts
 * import { EfsFilesystem, MultiContainerWorkload, defineConfig } from 'stacktape';
 *
 * export default defineConfig(() => {
 *   const sharedStorage = new EfsFilesystem({
 *     backupEnabled: true,
 *     throughputMode: 'elastic'
 *   });
 *
 *   const apiWorkload = new MultiContainerWorkload({
 *     containers: [
 *       {
 *         name: 'api-container',
 *         packaging: { type: 'prebuilt-image', properties: { image: 'my-repo/my-api' } },
 *         volumeMounts: [
 *           { type: 'efs', properties: { efsFilesystemName: 'sharedStorage', mountPath: '/data' } }
 *         ]
 *       }
 *     ],
 *     resources: { cpu: 1, memory: 2048 }
 *   });
 *
 *   return { resources: { sharedStorage, apiWorkload } };
 * });
 * ```
 */
export interface EfsFilesystem {
  type: "efs-filesystem";
  properties?: EfsFilesystemProps;
  /**
   * #### Escape hatch to modify the underlying CloudFormation resources Stacktape creates.
   *
   * ---
   *
   * Use dot-notation paths to override specific properties on any child resource.
   * Find resource logical IDs with `stacktape stack-info --detailed`.
   *
   * **Example (YAML):**
   *
   * ```yaml
   * resources:
   *   mainDb:
   *     type: relational-database
   *     properties:
   *       credentials:
   *         masterUserPassword: $Secret('db-password')
   *       engine:
   *         type: postgres
   *         properties:
   *           version: '16.2'
   *           primaryInstance:
   *             instanceSize: db.t3.micro
   *     overrides:
   *       MainDbDatabaseInstance:
   *         Properties.StorageEncrypted: true
   * ```
   *
   * **Example (TypeScript):**
   *
   * ```ts
   * import { RelationalDatabase, RdsEnginePostgres, $Secret, defineConfig } from 'stacktape';
   *
   * export default defineConfig(() => {
   *   const mainDb = new RelationalDatabase({
   *     credentials: { masterUserPassword: $Secret('db-password') },
   *     engine: new RdsEnginePostgres({
   *       version: '16.2',
   *       primaryInstance: { instanceSize: 'db.t3.micro' }
   *     }),
   *     overrides: {
   *       MainDbDatabaseInstance: { 'Properties.StorageEncrypted': true }
   *     }
   *   });
   *
   *   return { resources: { mainDb } };
   * });
   * ```
   */
  overrides?: {
    [k: string]: any;
  };
}
export interface EfsFilesystemProps {
  /**
   * #### Enable daily automatic backups with 35-day retention. Incremental (only changes are copied).
   *
   * ---
   *
   * **Example (YAML):**
   *
   * ```yaml
   * resources:
   *   mediaStorage:
   *     type: efs-filesystem
   *     properties:
   *       backupEnabled: true
   *       throughputMode: elastic
   *   cmsWorkload:
   *     type: multi-container-workload
   *     properties:
   *       containers:
   *         - name: cms
   *           packaging:
   *             type: prebuilt-image
   *             properties:
   *               image: my-repo/cms
   *           volumeMounts:
   *             - type: efs
   *               properties:
   *                 efsFilesystemName: mediaStorage
   *                 mountPath: /var/www/uploads
   *       resources:
   *         cpu: 0.5
   *         memory: 1024
   * ```
   *
   * **Example (TypeScript):**
   *
   * ```ts
   * import { EfsFilesystem, MultiContainerWorkload, defineConfig } from 'stacktape';
   *
   * export default defineConfig(() => {
   *   const mediaStorage = new EfsFilesystem({
   *     backupEnabled: true,
   *     throughputMode: 'elastic'
   *   });
   *
   *   const cmsWorkload = new MultiContainerWorkload({
   *     containers: [
   *       {
   *         name: 'cms',
   *         packaging: { type: 'prebuilt-image', properties: { image: 'my-repo/cms' } },
   *         volumeMounts: [
   *           { type: 'efs', properties: { efsFilesystemName: 'mediaStorage', mountPath: '/var/www/uploads' } }
   *         ]
   *       }
   *     ],
   *     resources: { cpu: 0.5, memory: 1024 }
   *   });
   *
   *   return { resources: { mediaStorage, cmsWorkload } };
   * });
   * ```
   */
  backupEnabled?: boolean;
  /**
   * #### How throughput scales with your workload.
   *
   * ---
   *
   * - **`elastic`** (recommended): Auto-scales throughput. Best for spiky workloads (web apps, CI/CD).
   * - **`provisioned`**: Fixed throughput you set via `provisionedThroughputInMibps`. Best for steady high-throughput workloads.
   * - **`bursting`**: Throughput scales with storage size (50 KiB/s per GiB). Can run out of burst credits.
   *
   *
   * **Example (YAML):**
   *
   * ```yaml
   * resources:
   *   modelStorage:
   *     type: efs-filesystem
   *     properties:
   *       backupEnabled: false
   *       throughputMode: provisioned
   *       provisionedThroughputInMibps: 100
   *   inferenceWorkload:
   *     type: multi-container-workload
   *     properties:
   *       containers:
   *         - name: inference
   *           packaging:
   *             type: prebuilt-image
   *             properties:
   *               image: my-repo/ml-inference
   *           volumeMounts:
   *             - type: efs
   *               properties:
   *                 efsFilesystemName: modelStorage
   *                 mountPath: /models
   *       resources:
   *         cpu: 2
   *         memory: 4096
   * ```
   *
   * **Example (TypeScript):**
   *
   * ```ts
   * import { EfsFilesystem, MultiContainerWorkload, defineConfig } from 'stacktape';
   *
   * export default defineConfig(() => {
   *   const modelStorage = new EfsFilesystem({
   *     backupEnabled: false,
   *     throughputMode: 'provisioned',
   *     provisionedThroughputInMibps: 100
   *   });
   *
   *   const inferenceWorkload = new MultiContainerWorkload({
   *     containers: [
   *       {
   *         name: 'inference',
   *         packaging: { type: 'prebuilt-image', properties: { image: 'my-repo/ml-inference' } },
   *         volumeMounts: [
   *           { type: 'efs', properties: { efsFilesystemName: 'modelStorage', mountPath: '/models' } }
   *         ]
   *       }
   *     ],
   *     resources: { cpu: 2, memory: 4096 }
   *   });
   *
   *   return { resources: { modelStorage, inferenceWorkload } };
   * });
   * ```
   */
  throughputMode?: "bursting" | "elastic" | "provisioned";
  /**
   * #### Guaranteed throughput in MiB/s. Required when `throughputMode` is `provisioned`.
   *
   * ---
   *
   * E.g., `100` = 100 MiB/s. Additional fees apply based on the provisioned amount. Can be changed anytime.
   *
   * **Example (YAML):**
   *
   * ```yaml
   * resources:
   *   highThroughputStorage:
   *     type: efs-filesystem
   *     properties:
   *       throughputMode: provisioned
   *       provisionedThroughputInMibps: 256
   *   dataWorkload:
   *     type: multi-container-workload
   *     properties:
   *       containers:
   *         - name: processor
   *           packaging:
   *             type: prebuilt-image
   *             properties:
   *               image: my-repo/data-processor
   *           volumeMounts:
   *             - type: efs
   *               properties:
   *                 efsFilesystemName: highThroughputStorage
   *                 mountPath: /shared
   *       resources:
   *         cpu: 4
   *         memory: 8192
   * ```
   *
   * **Example (TypeScript):**
   *
   * ```ts
   * import { EfsFilesystem, MultiContainerWorkload, defineConfig } from 'stacktape';
   *
   * export default defineConfig(() => {
   *   const highThroughputStorage = new EfsFilesystem({
   *     throughputMode: 'provisioned',
   *     provisionedThroughputInMibps: 256
   *   });
   *
   *   const dataWorkload = new MultiContainerWorkload({
   *     containers: [
   *       {
   *         name: 'processor',
   *         packaging: { type: 'prebuilt-image', properties: { image: 'my-repo/data-processor' } },
   *         volumeMounts: [
   *           { type: 'efs', properties: { efsFilesystemName: 'highThroughputStorage', mountPath: '/shared' } }
   *         ]
   *       }
   *     ],
   *     resources: { cpu: 4, memory: 8192 }
   *   });
   *
   *   return { resources: { highThroughputStorage, dataWorkload } };
   * });
   * ```
   */
  provisionedThroughputInMibps?: number;
}
